import { html, customElement, property, css, state } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import type { UUIInputEvent } from '@umbraco-ui/uui-input';
import type { UUISelectEvent } from '@umbraco-ui/uui';
import type { Field } from '@umbraco-forms/generated';
import { FORMS_FORM_WORKSPACE_CONTEXT } from '../../section/forms/workspace/form-workspace.context-token.js';

const elementName = "text-with-field-picker-property-editor";
const FREE_TEXT: string = "FREE_TEXT";
const FIELD_PICKER: string = "FIELD_PICKER";

@customElement(elementName)
export class FormsTextWithFieldPickerPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {
  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;
  #fieldSelectOptions: Array<Field> = [];

  @state()
  inputMode = "";

  #value = "";
  @property()
  get value() {
    this.inputMode = this.#isMagicString(this.#value) ? FIELD_PICKER : FREE_TEXT;   //Check current input mode when dialog is opened.
    return this.#value;
  }
  set value(value: string) {
    const oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);
  }

  constructor() {
    super();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
			this.#workspaceContext = instance;
      this.#initializeFieldSelectOptions();
		});
  }

  #initializeFieldSelectOptions() {
    this.#fieldSelectOptions = this.#workspaceContext!.getAllFields();
  }

  #changeInputMode(value: string) {
    this.inputMode = value;
  }

  #onTextBoxChange(e: UUIInputEvent) {
    const textValue = e.target.value.toString();

    if (this.#isFieldMagicString(textValue)) {
      this.#value = this.#deMagic(textValue);
    }
    else {
      this.#value = textValue;
    }

    this.#refreshValue();
  }

  #onFieldSelectChange(e: UUISelectEvent) {
    this.#value = this.#toMagicString(e.target.value.toString());
    this.#refreshValue();
  }

  #refreshValue() {
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  /**
     * Convert any input string into a magic string by appending '{' and '}'.
     * @param {string} input
     * @returns {string} original input string if it's a magic string already. Returns '' if input is falsy.
     */
  #toMagicString(input) {
    if (!input) {
      return '';
    };

    if (this.#isMagicString(input)) {
      return input;
    }

    return `{${input}}`;
  }

  /**
   * Convert any magic string into a normal text.
   * @param {string} input
   * @returns {string} normal text which is not wrapped by {}. Returns original input string if it is NOT a magic string.
   */
  #deMagic(input) {
    return this.#isMagicString(input) ? input.substring(1, this.#value.length - 1) : input;
  }

  #isMagicString(input) {
    const regex = new RegExp(/^{\w+}$/gi);
    return !!input && regex.test(input);
  }

  /**
   * Check if the input string actually a magic string of a field.
   * @param {string} input
   */
  #isFieldMagicString(input) {
    if (!this.#isMagicString(input)) {
      return false;
    }

    const fieldAliases = this.#workspaceContext!.getAllFields().map(field => field.alias);
    return fieldAliases.includes(this.#deMagic(input));
  }

  #isFreeTextMode() {
    return this.inputMode === FREE_TEXT;
  }

  render() {
    return html`
      <uui-button-group>
        <uui-button label="Free text" look=${this.#isFreeTextMode() ? "primary" : "secondary"} color="default" @click=${() => this.#changeInputMode(FREE_TEXT)}></uui-button>
        <uui-button label="Select field" look=${!this.#isFreeTextMode() ? "primary" : "secondary"} color="default" @click=${() => this.#changeInputMode(FIELD_PICKER)}></uui-button>
      </uui-button-group>
      ${this.#isFreeTextMode() ?
        html`
          <div class="text-with-field-picker-margin-div">
            <uui-input
              type="text"
              .value=${this.#value}
              @change=${(e: UUIInputEvent) => this.#onTextBoxChange(e)}>
            </uui-input>
          </div>
        ` : html`
          <div class="text-with-field-picker-margin-div">
            <uui-select
              .options=${this.#fieldSelectOptions.map((f: Field) => ({
                name: f.caption,
                value: f.alias,
                selected: f.alias === this.#deMagic(this.#value),
              })) ?? []}
              placeholder="Select a field"
              @change=${(e: UUISelectEvent) => this.#onFieldSelectChange(e)}>
            </uui-select>
          </div>
        `}
    `;
  }

  static styles = [
    css`
      .text-with-field-picker-margin-div{
        margin-top: var(--uui-size-3);
      }
    `
  ];
}

export default FormsTextWithFieldPickerPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsTextWithFieldPickerPropertyUiElement;
    }
}
